test_config.test_file:
import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import App from './App';

describe('Holy Grail Layout', () => {
  beforeEach(() => {
    render(<App />);
  });

  it('uses CSS Grid', () => {
    expect(getComputedStyle(screen.getByTestId('holy-grail')).display).toBe('grid');
  });

  it('fills viewport height', () => {
    expect(getComputedStyle(screen.getByTestId('holy-grail')).minHeight).toBe('100vh');
  });

  it('header has grid-area header', () => {
    expect(getComputedStyle(screen.getByTestId('header')).gridArea).toMatch(/header/);
  });

  it('nav has grid-area nav', () => {
    expect(getComputedStyle(screen.getByTestId('nav')).gridArea).toMatch(/nav/);
  });

  it('main has grid-area main', () => {
    expect(getComputedStyle(screen.getByTestId('main')).gridArea).toMatch(/main/);
  });

  it('aside has grid-area aside', () => {
    expect(getComputedStyle(screen.getByTestId('aside')).gridArea).toMatch(/aside/);
  });

  it('footer has grid-area footer', () => {
    expect(getComputedStyle(screen.getByTestId('footer')).gridArea).toMatch(/footer/);
  });

  it('header has dark background', () => {
    expect(getComputedStyle(screen.getByTestId('header')).backgroundColor).toBe('rgb(30, 41, 59)');
  });

  it('nav has light background', () => {
    expect(getComputedStyle(screen.getByTestId('nav')).backgroundColor).toBe('rgb(241, 245, 249)');
  });

  it('footer has dark background', () => {
    expect(getComputedStyle(screen.getByTestId('footer')).backgroundColor).toBe('rgb(30, 41, 59)');
  });

  it('main has white background', () => {
    const bg = getComputedStyle(screen.getByTestId('main')).backgroundColor;
    expect(bg === 'rgb(255, 255, 255)' || bg === 'rgba(0, 0, 0, 0)' || bg === 'white').toBeTruthy();
  });
});

solution_files.content:
.holy-grail {
  display: grid;
  grid-template-areas:
    "header header header"
    "nav main aside"
    "footer footer footer";
  grid-template-columns: 12rem 1fr 12rem;
  grid-template-rows: auto 1fr auto;
  min-height: 100vh;
}

.hg-header {
  grid-area: header;
  background-color: #1e293b;
  color: #ffffff;
  padding: 1rem 1.5rem;
}

.hg-header h1 {
  margin: 0;
  font-size: 1.125rem;
}

.hg-nav {
  grid-area: nav;
  background-color: #f1f5f9;
  padding: 1.25rem;
  border-right: 1px solid #e2e8f0;
}

.hg-nav h2 {
  margin: 0 0 0.75rem;
  font-size: 0.875rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #64748b;
}

.hg-nav ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

.hg-nav li {
  margin-bottom: 0.375rem;
}

.hg-nav a {
  color: #334155;
  text-decoration: none;
  font-size: 0.875rem;
}

.hg-main {
  grid-area: main;
  padding: 2rem;
  background-color: #ffffff;
}

.hg-main h2 {
  margin: 0 0 0.75rem;
  font-size: 1.25rem;
  color: #0f172a;
}

.hg-main p {
  margin: 0;
  color: #475569;
  line-height: 1.6;
}

.hg-aside {
  grid-area: aside;
  background-color: #f1f5f9;
  padding: 1.25rem;
  border-left: 1px solid #e2e8f0;
}

.hg-aside h2 {
  margin: 0 0 0.75rem;
  font-size: 0.875rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #64748b;
}

.hg-aside p {
  margin: 0;
  font-size: 0.875rem;
  color: #475569;
}

.hg-footer {
  grid-area: footer;
  background-color: #1e293b;
  color: #ffffff;
  padding: 1rem 1.5rem;
  text-align: center;
}

.hg-footer p {
  margin: 0;
  font-size: 0.8125rem;
}
